    function applyLayout(){if(!appRoot)return;restoreRootLayout();host.dataset.layoutMode=boot.layoutMode||"overlay";if(!dockVisible||boot.layoutMode==="overlay"||position==="floating")return;const rect=dock.getBoundingClientRect(),reserve=Math.min(440,Math.ceil(rect.width));if(innerWidth-reserve<720){host.dataset.layoutMode="overlay-fallback";return;}if(position==="right_dock"){appRoot.style.width=`calc(100vw - ${reserve}px)`;appRoot.style.maxWidth=appRoot.style.width;if(appShell){appShell.style.width=appRoot.style.width;appShell.style.maxWidth=appRoot.style.maxWidth;}}else if(position==="left_dock"){appRoot.style.width=`calc(100vw - ${reserve}px)`;appRoot.style.maxWidth=appRoot.style.width;appRoot.style.marginLeft=`${reserve}px`;if(appShell){appShell.style.width=appRoot.style.width;appShell.style.maxWidth=appRoot.style.maxWidth;}}else if(position==="bottom_dock"){const height=Math.min(280,Math.ceil(rect.height));if(innerHeight-height<520){host.dataset.layoutMode="overlay-fallback";return;}appRoot.style.height=`calc(100vh - ${height}px)`;appRoot.style.maxHeight=appRoot.style.height;if(appShell){appShell.style.height=appRoot.style.height;appShell.style.maxHeight=appRoot.style.maxHeight;}}}
