    function findComposerToggleGroup(){const editors=[...document.querySelectorAll('[contenteditable="true"]')].filter(editor=>{const rect=editor.getBoundingClientRect(),style=getComputedStyle(editor);return style.visibility!=="hidden"&&style.display!=="none"&&rect.width>200&&rect.height>20&&rect.bottom>innerHeight*.55;}).sort((a,b)=>b.getBoundingClientRect().bottom-a.getBoundingClientRect().bottom);for(const editor of editors){let shell=editor.parentElement;for(let depth=0;shell&&depth<9;depth++,shell=shell.parentElement){const children=[...shell.children];if(children.length!==3)continue;const editorChild=children.find(child=>child===editor||child.contains(editor));if(!editorChild)continue;const controls=children.filter(child=>child!==editorChild&&child.querySelector("button"));if(controls.length!==2)continue;const editorRect=editor.getBoundingClientRect(),controlRects=controls.map(child=>child.getBoundingClientRect());if(controlRects.some(rect=>rect.top<editorRect.top||rect.width<24))continue;const left=controls.sort((a,b)=>a.getBoundingClientRect().left-b.getBoundingClientRect().left)[0];const group=left.firstElementChild&&left.firstElementChild.querySelector("button")?left.firstElementChild:left;if(!group.querySelector("button"))continue;return group;}}return null;}
    function createComposerToggle(template){const button=document.createElement("button");button.type="button";button.dataset.codexUsageDockToggle="1";button.className=template.className;button.style.cssText=template.style.cssText;button.innerHTML='<svg aria-hidden="true" viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="16" rx="2"></rect><path d="M15 4v16"></path><path d="M17.75 8h.5M17.75 12h.5M17.75 16h.5"></path></svg>';button.addEventListener("click",event=>{event.preventDefault();event.stopPropagation();setDockVisible(!dockVisible);});return button;}
