    function promptStructure(editor){const text=String(editor?.innerText||"");const lines=text?text.split(/\r?\n/):[];const sectionCount=lines.filter(line=>/^\s*(#{1,6}|[A-ZА-ЯІЇЄ][^:]{1,50}:)\s*/u.test(line)).length;const taskCount=lines.filter(line=>/^\s*(?:[-*]|\d+[.)])\s+/.test(line)).length;return{char_count:text.length,line_count:lines.length,section_count:sectionCount,task_count:taskCount,multi_task:taskCount>=2};}
