    function compact(value){const n=finite(value);return n===null?"—":new Intl.NumberFormat(locale,{notation:"compact",maximumFractionDigits:1}).format(n);}
    function duration(value){let n=finite(value);if(n===null)return"—";n=Math.max(0,Math.round(n));const h=Math.floor(n/3600),m=Math.floor(n%3600/60),s=n%60;if(language==="uk"){if(h)return`${h} год ${m} хв`;if(m)return`${m} хв ${s} с`;return`${s} с`;}if(h)return`${h}h ${m}m`;if(m)return`${m}m ${s}s`;return`${s}s`;}
